parsed.api_descriptions:
API_name: nchu_course_search_selectable_courses
Description:
{
  "description": "Search courses that students of a specific department and academic level CAN ENROLL in. This is different from nchu_course_search_by_department which only finds courses OFFERED by a department. This tool finds all courses that a department's students are eligible to enroll in, including: - Courses offered by the same department - Courses offered by OTHER departments but designated for this department's students Academic level rules: - 學士班 (Undergraduate): Can enroll in 學士班 + 碩士班 courses - 碩士班 (Master): Can enroll in 碩士班 + 博士班 courses (NOT undergraduate courses) - 博士班 (PhD): Can enroll in 博士班 courses only - 碩專班 (Executive Master): Can enroll in 碩專班 + 碩士班 + 博士班 courses JSON string containing: - results: List of selectable courses with enrollment info - summary: Count of same-dept vs other-dept courses - search_params: Parameters used for the search including selectable career levels",
  "required_parameters": [
    {
      "name": "department",
      "type": "STRING",
      "description": "Department name keyword (e.g., \"資工\", \"電機\", \"中文\")"
    }
  ],
  "optional_parameters": [
    {
      "name": "career",
      "type": "STRING",
      "description": "Academic level - 學士班, 碩士班, 博士班, 碩專班, 進修學士班 (default: 學士班)",
      "default": "學士班"
    },
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "Maximum number of results to return (default: 20)",
      "default": 20
    },
    {
      "name": "include_other_dept",
      "type": "BOOLEAN",
      "description": "Include courses offered by other departments but selectable by this department (default: True)",
      "default": true
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code. If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

parsed.action_input:
{
  "department": "生物產業機電系",
  "career": "學士班",
  "include_other_dept": true
}

